mapper.insert:
INSERT INTO MCP_USER_PROMOTION
(
    USER_PROMO_ID               --프로모션 키 MCP_USER_PROMOTION_SEQ
     , USERID                   --아이디
     , INTEREST_CODE            --관심사코드(공통코드 2차)
     , PROMOTION_CODE           --프로모션 코드(공통코드 2차)
     , USE_TEL_CODE             --통신사 코드
     , CRET_DD                  --생성일
     , CRET_ID                  --생성자아이디
     , AMD_ID                   --수정자ID
     , CRET_DT                  --생성일시
     , AMD_DT                   --수정일시
     , RIP                      --등록아이피

) VALUES (

    MCP_USER_PROMOTION_SEQ .NEXTVAL
     , #{userId}
     , #{interestCode}
     , #{promotionCode}
     , #{useTelCode}
     , TO_CHAR(SYSDATE, 'YYYYMMDD')
     , #{userId}
     , #{userId}
     , SYSDATE
     , SYSDATE
     , #{rip}
)

mapper.delete:
DELETE FROM MCP_USER_PROMOTION
WHERE 1=1
AND USERID = #{userId}
